body.script:
// Set the content type to XML
document.contentType = 'application/xml';

async function generateSitemap() {
  const baseUrl = 'https://shalomkarr.pages.dev';
  const today = new Date().toISOString().split('T')[0];

  // Static pages with priority and change frequency
  const staticPages = [
    { url: '/', changefreq: 'monthly', priority: '1.0', lastmod: today },
    { url: '/blog/', changefreq: 'daily', priority: '0.9', lastmod: today },
    { url: '/blog/contact/', changefreq: 'monthly', priority: '0.7', lastmod: today },
  ];

  let xml = '\n';
  xml += '\n';

  // Add static pages
  staticPages.forEach(page => {
    xml += '  \n';
    xml += `    ${baseUrl}${page.url}\n`;
    xml += `    ${page.lastmod}\n`;
    xml += `    ${page.changefreq}\n`;
    xml += `    ${page.priority}\n`;
    xml += '  \n';
  });

  // Fetch and add blog posts
  if (window.supabaseClient) {
    try {
      const { data: posts, error } = await window.supabaseClient
        .from('posts')
        .select('slug, updated_at, created_at')
        .eq('is_published', true)
        .order('created_at', { ascending: false });

      if (!error && posts) {
        posts.forEach(post => {
          const lastmod = post.updated_at || post.created_at;
          const formattedDate = new Date(lastmod).toISOString().split('T')[0];

          xml += '  \n';
          xml += `    ${baseUrl}/blog/post.html?slug=${encodeURIComponent(post.slug)}\n`;
          xml += `    ${formattedDate}\n`;
          xml += `    weekly\n`;
          xml += `    0.8\n`;
          xml += '  \n';
        });
      }
    } catch (e) {
      console.error('Error fetching posts:', e);
    }
  }

  xml += '';

  // Output the XML
  document.open();
  document.write(xml);
  document.close();
}

// Wait for Supabase client to be initialized
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', generateSitemap);
} else {
  generateSitemap();
}
